                ОсновнаКартинкаФайл = new Довідники.Файли_Pointer(base.FieldValue["col_a7"]);
                
                BaseClear();
                
                if (readAllTablePart)
                {
                    
                    await Файли_TablePart.Read();
                }
                
                Caption = string.Join(", ", [Назва, ]);
                return true;
            }
