            base.FieldValue["col_a7"] = ОсновнаКартинкаФайл.UniqueID.UGuid;
            
            bool result = await BaseSave();
            if (result)
            {
                
                await BaseWriteFullTextSearch(GetBasis(), [Назва, НазваПовна, Опис, Артикул, ]);
                
