                Основа = (base.FieldValue["col_a3"] != DBNull.Value) ? (UuidAndText)base.FieldValue["col_a3"] : new UuidAndText();
                
                BaseClear();
                
                if (readAllTablePart)
                {
                    
                    await Контакти_TablePart.Read();
                }
                
                Caption = string.Join(", ", [Назва, ]);
                return true;
