                СпосібДоставки = СпосібДоставки,
                ЧасДоставкиЗ = ЧасДоставкиЗ,
                ЧасДоставкиДо = ЧасДоставкиДо,
                ПовернутиТару = ПовернутиТару,
                ДатаПоверненняТари = ДатаПоверненняТари,
                Коментар = Коментар,
                Менеджер = Менеджер,
                КлючовіСловаДляПошуку = КлючовіСловаДляПошуку,
                Основа = Основа,
                
            };
            
