        {
            base.Init(new UniqueID(uid));
        }
        
        public ПереміщенняТоварів_Pointer(UniqueID uid, Dictionary<string, object>? fields = null) : base(Config.Kernel, "tab_a31", "ПереміщенняТоварів")
        {
