            public string Штрихкод { get; set; } = "";
            public Документи.РеалізаціяТоварівТаПослуг_Pointer ДокументРеалізації { get; set; } = new Документи.РеалізаціяТоварівТаПослуг_Pointer();
            
        }
    }
      
    
