                Валюта = Валюта,
                Підрозділ = Підрозділ,
                СумаДокументу = СумаДокументу,
                Основа = Основа,
                Автор = Автор,
                ГосподарськаОперація = ГосподарськаОперація,
                Коментар = Коментар,
                КлючовіСловаДляПошуку = КлючовіСловаДляПошуку,
                
