                await Товари_TablePart.Read();
                copy.Товари_TablePart.Records = Товари_TablePart.Copy();
            
            }
            

            await copy.New();
            
                await ВнутрішнєСпоживанняТоварів_Triggers.Copying(copy, this);      
            
            return copy;
        }

