    public class РозміщенняТоварівНаСкладі_Select : DocumentSelect
    {		
        public РозміщенняТоварівНаСкладі_Select() : base(Config.Kernel, "tab_a64") { }
        public async ValueTask<bool> Select() { return await base.BaseSelect(); }
