		    public static readonly string[] AllowDocumentSpendTable = ["tab_b51", ];
		    public static readonly string[] AllowDocumentSpendType = ["ЧекККМ", ];
        
        public const string Організація = "col_a1";
        public const string КасаККМ = "col_a2";
